#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define ONE_WIRE_BUS 2
#define SSR_PIN 6
#define BUZZER 8
#define LED 9
#define SD_CS 10
#define N_SENSORS 8
#define SP_DT 15.0f
#define WARN_DT 18.0f
#define FAULT_DT 22.0f
#define DT_S 1.0f
OneWire ow(ONE_WIRE_BUS); DallasTemperature ds(&ow);
float intg=0,lastE=0;

int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float*intg,float*lastE){
  float e=pv-sp;
  *intg+=e*dt; *intg=constrain(*intg,0,255);
  float d=(e-*lastE)/dt; *lastE=e;
  return (int)constrain(kp*e+ki*(*intg)+kd*d,0,255);
}

float read_delta_T(){
  ds.requestTemperatures();
  float core=ds.getTempCByIndex(0),surf=0;
  for(int i=1;i<N_SENSORS;i++) surf+=ds.getTempCByIndex(i);
  return core-surf/(N_SENSORS-1);
}

void run_cooling(float dT){
  int duty=pid_heater_control(SP_DT,dT,DT_S,12.0f,0.4f,1.0f,&intg,&lastE);
  analogWrite(SSR_PIN,duty);
}

void run_alarm(float dT){
  if(dT>=FAULT_DT){tone(BUZZER,2000);analogWrite(LED,255);}
  else if(dT>=WARN_DT){tone(BUZZER,1000);analogWrite(LED,128);}
  else{noTone(BUZZER);analogWrite(LED,0);}
}

void log_sd(float dT){
  File f=SD.open("curing.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.println(dT);f.close();}
}

void setup(){Serial.begin(115200);ds.begin();SD.begin(SD_CS);pinMode(SSR_PIN,OUTPUT);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);}

void loop(){float dT=read_delta_T();run_cooling(dT);run_alarm(dT);log_sd(dT);Serial.print("dT=");Serial.println(dT);delay(1000);}
